class Solution {

    public List<Integer> parseNestedParens(String paren_string) {
        List<Integer> result = new ArrayList<>();
        int wsIndex = 1;
        int wsMaxDepth = 0;
        int wsCurrentDepth = 0;
        int wsLength = paren_string.length();
        for (int wsI = 0; wsI < wsLength; wsI++) {
            char wsChar = paren_string.charAt(wsI);
            switch (wsChar) {
                case '(':
                    wsCurrentDepth++;
                    if (wsCurrentDepth > wsMaxDepth) {
                        wsMaxDepth = wsCurrentDepth;
                    }
                    break;
                case ')':
                    wsCurrentDepth--;
                    break;
                case ' ':
                    result.add(wsMaxDepth);
                    wsIndex++;
                    wsMaxDepth = 0;
                    wsCurrentDepth = 0;
                    break;
            }
        }
        result.add(wsMaxDepth);
        return result;
    }
}

