class Solution {

    public int greatestCommonDivisor(int a, int b) {
        int wsTempA = a;
        int wsTempB = b;
        int wsRemainder;

        if (wsTempA < 0) {
            wsTempA = wsTempA * -1;
        }

        if (wsTempB < 0) {
            wsTempB = wsTempB * -1;
        }

        while (wsTempB != 0) {
            wsRemainder = wsTempA % wsTempB;
            wsTempA = wsTempB;
            wsTempB = wsRemainder;
        }

        return wsTempA;
    }
