class Solution {

    public int howManyTimes(String string, String substring) {
        int wsStringLength = 0;
        int wsSubstringLength = 0;
        int wsCurrentPos = 0;
        int wsCount = 0;
        char wsMatchFound = 'N';
        int wsI = 0;
        int wsJ = 0;
        int result = 0;

        // Get length of input string
        for (wsI = 0; wsI < string.length(); wsI++) {
            if (string.charAt(wsI) == ' ') {
                break;
            }
        }
        wsStringLength = wsI;

        // Get length of substring
        for (wsI = 0; wsI < substring.length(); wsI++) {
            if (substring.charAt(wsI) == ' ') {
                break;
            }
        }
        wsSubstringLength = wsI;

        // Handle edge cases
        if (wsSubstringLength == 0) {
            result = 0;
            return result;
        }

        if (wsStringLength < wsSubstringLength) {
            result = 0;
            return result;
        }

        // Search for substring at each position
        wsCount = 0;
        for (wsCurrentPos = 0; wsCurrentPos <= wsStringLength - wsSubstringLength; wsCurrentPos++) {
            wsMatchFound = 'Y';
            for (wsJ = 0; wsJ < wsSubstringLength; wsJ++) {
                if (wsCurrentPos + wsJ >= string.length() || wsJ >= substring.length()) {
                    break;
                }
                if (string.charAt(wsCurrentPos + wsJ) != substring.charAt(wsJ)) {
                    wsMatchFound = 'N';
                    break;
                }
            }
            if (wsMatchFound == 'Y') {
                wsCount++;
            }
        }

        result = wsCount;
        return result;
    }
}

