            }
        }
        for (int i = 0; i < count - 1; i++) {
            for (int j = 0; j < count - i - 1; j++) {
                if (nums[j] > nums[j + 1]) {
                    int tmp = nums[j];
                    nums[j] = nums[j + 1];
                    nums[j + 1] = tmp;
                }
            }
        }
        StringBuilder result = new StringBuilder();
        for (int i = 0; i < count; i++) {
            String tmp;
            switch (nums[i]) {
                case 0: tmp = "zero"; break;
