class Solution {

    public List<Double> rescaleToUnit(List<Double> numbers) {
        double wsMinValue = numbers.get(0);
        double wsMaxValue = numbers.get(0);
        int wsCount = numbers.size();
        for (int i = 1; i < wsCount; i++) {
            if (numbers.get(i) < wsMinValue) {
                wsMinValue = numbers.get(i);
            }
            if (numbers.get(i) > wsMaxValue) {
                wsMaxValue = numbers.get(i);
            }
        }
        double wsRange = wsMaxValue - wsMinValue;
        List<Double> result = new ArrayList<>(Collections.nCopies(100, 0.0));
        for (int i = 0; i < wsCount; i++) {
            double wsTemp = numbers.get(i) - wsMinValue;
            result.set(i, wsTemp / wsRange);
        }
        return result;
    }
}

