class Solution {

    public int strlen(String string) {
        int result = 0;
        int wsLength = 0;
        int wsStartPos = 1;
        int wsEndPos = 0;
        int wsI = 1;

        for (wsI = 1; wsI <= 100; wsI++) {
            if (wsI <= string.length() && string.charAt(wsI - 1) != ' ') {
                wsStartPos = wsI;
                break;
            }
        }

        if (wsI > 100) {
            result = 0;
            return result;
        }

        for (wsI = 100; wsI >= 1; wsI--) {
            if (wsI <= string.length() && string.charAt(wsI - 1) != ' ') {
                wsEndPos = wsI;
                break;
            }
        }

        wsLength = wsEndPos - wsStartPos + 1;
        result = wsLength;

        return result;
    }
}

