class Solution {

    public int largestDivisor(int n) {
        int result = 0;
        if (n <= 1) {
            return result;
        }
        int divisor = n - 1;
        while (divisor != 0) {
            int remainder = n % divisor;
            if (remainder == 0) {
                result = divisor;
                break;
            }
            divisor--;
        }
        return result;
    }
}

