class Solution {

    public List<Integer> unique(List<Integer> l) {
        List<Integer> result = new ArrayList<>(Collections.nCopies(100, 0));
        int wsLen = 9;
        int wsK = 1;
        int wsTmp;

        for (int wsI = 0; wsI < wsLen - 1; wsI++) {
            for (int wsJ = 0; wsJ < wsLen - wsI - 1; wsJ++) {
                if (l.get(wsJ) > l.get(wsJ + 1)) {
                    wsTmp = l.get(wsJ);
                    l.set(wsJ, l.get(wsJ + 1));
                    l.set(wsJ + 1, wsTmp);
                }
            }
        }

        result.set(wsK - 1, l.get(0));

        for (int wsI = 1; wsI < wsLen; wsI++) {
            if (!l.get(wsI).equals(result.get(wsK - 1))) {
                wsK++;
                result.set(wsK - 1, l.get(wsI));
            }
        }

        return result.subList(0, wsK);
    }
}

