class Solution {

    public int primeFib(int n) {
        int count = 0;
        int fibA = 1;
        int fibB = 1;
        int fibCurrent = 0;
        int temp = 0;
        int i = 0;
        int sqrt = 0;
        boolean isPrime = false;

        while (count != n) {
            fibCurrent = fibA;
            fibA = fibB;
            fibB = fibCurrent + fibB;

            if (fibCurrent > 1) {
                isPrime = true;

                if (fibCurrent < 2) {
                    isPrime = false;
                } else if (fibCurrent == 2) {
                    isPrime = true;
                } else {
                    temp = fibCurrent / 2;
                    if (fibCurrent == temp * 2) {
                        isPrime = false;
                    } else {
                        sqrt = (int) Math.sqrt(fibCurrent);
                        sqrt += 1;
                        for (i = 3; i <= sqrt; i += 2) {
                            temp = fibCurrent / i;
                            if (fibCurrent == temp * i) {
                                isPrime = false;
                                break;
                            }
                        }
                    }
                }

                if (isPrime) {
                    count++;
                    if (count == n) {
                        return fibCurrent;
                    }
                }
            }
        }

        return -1;
    }
}

