class Solution {

    public String changeBase(int x, int base) {
        char[] digits = new char[100];
        int absX = x;
        boolean negative = false;
        int digCnt = 0;
        int pos = 0;
        int q, r;
        String result = "";

        if (absX < 0) {
            negative = true;
            absX = -absX;
        }

        if (absX == 0) {
            return "0";
        }

        if (base == 1) {
            if (negative) {
                result = "-";
                pos = 2;
            } else {
                pos = 1;
            }
            for (int i = 1; i <= absX && pos <= 100; i++) {
                result += "1";
                pos++;
            }
            return result;
        }

        while (absX != 0) {
            q = absX / base;
            r = absX % base;
            digCnt++;
            if (digCnt <= 100) {
                digits[digCnt - 1] = (char) ('0' + r);
            }
            absX = q;
        }

        if (negative) {
            result = "-";
            pos = 2;
        } else {
            pos = 1;
        }

        for (int i = digCnt - 1; i >= 0 && pos <= 100; i--) {
            result += digits[i];
            pos++;
        }

        return result;
    }
}

