class Solution {

    public double triangleArea(double a, double b, double c) {
        double s;
        double prod;
        double area;
        double area2dp;
        double result;

        if (a <= 0 || b <= 0 || c <= 0) {
            return -1;
        }

        if ((a + b) <= c || (a + c) <= b || (b + c) <= a) {
            return -1;
        }

        s = (a + b + c) / 2;
        prod = s * (s - a) * (s - b) * (s - c);

        if (prod < 0) {
            prod = 0;
        }

        area = Math.sqrt(prod);
        area2dp = Math.round(area * 100.0) / 100.0;
        result = area2dp;

        return result;
    }
}

