class Solution {

    public boolean isMultiplyPrime(int a) {
        int wsNum = a;
        int wsFactor = 2;
        int wsPrimeCount = 0;
        int wsTempNum = wsNum;
        int wsIsPrime = 0;
        int wsSqrt = 0;
        int wsI = 0;
        int result = 0;

        if (wsNum <= 1) {
            result = 0;
            return result == 1;
        }

        while (wsFactor * wsFactor <= wsTempNum) {
            while (wsTempNum % wsFactor == 0) {
                wsIsPrime = 1;
                if (wsFactor <= 1) {
                    wsIsPrime = 0;
                } else if (wsFactor == 2) {
                    wsIsPrime = 1;
                } else if (wsFactor % 2 == 0) {
                    wsIsPrime = 0;
                } else {
                    wsSqrt = (int) Math.sqrt(wsFactor);
                    wsI = 3;
                    while (wsI <= wsSqrt) {
                        if (wsFactor % wsI == 0) {
                            wsIsPrime = 0;
                            break;
                        }
                        wsI += 2;
                    }
                }
                if (wsIsPrime == 1) {
                    wsPrimeCount++;
                }
                wsTempNum /= wsFactor;
            }
            wsFactor++;
        }

        if (wsTempNum > 1) {
            wsFactor = wsTempNum;
            wsIsPrime = 1;
            if (wsFactor <= 1) {
                wsIsPrime = 0;
            } else if (wsFactor == 2) {
                wsIsPrime = 1;
            } else if (wsFactor % 2 == 0) {
                wsIsPrime = 0;
            } else {
                wsSqrt = (int) Math.sqrt(wsFactor);
                wsI = 3;
                while (wsI <= wsSqrt) {
                    if (wsFactor % wsI == 0) {
                        wsIsPrime = 0;
                        break;
                    }
                    wsI += 2;
                }
            }
            if (wsIsPrime == 1) {
                wsPrimeCount++;
            }
        }

        if (wsPrimeCount == 3) {
            result = 1;
        } else {
            result = 0;
        }

        return result == 1;
    }
}

