                        result[outIndex++] = charBuf[k];
                    }
                    wordLen = 0;
                }
                result[outIndex++] = ' ';
            } else {
                charBuf[wordLen++] = curChar;
            }
        }
        if (wordLen > 0) {
            for (int p = 1; p <= wordLen; p++) {
                char tempChar = charBuf[p - 1];
                int q = p - 1;
                while (q > 0 && charBuf[q - 1] > tempChar) {
                    charBuf[q] = charBuf[q - 1];
                    q--;
                }
                charBuf[q] = tempChar;
            }
            for (int k = 0; k < wordLen; k++) {
                result[outIndex++] = charBuf[k];
            }
        }
        return new String(result, 0, outIndex);
    }
}

