class Solution {

    public Object roundedAvg(int n, int m) {
        if (n > m) {
            return "-1";
        }
        long sum = 0;
        int count = 0;
        for (int i = n; i <= m; i++) {
            sum += i;
            count++;
        }
        double avg = (double) sum / count;
        long rounded = Math.round(avg);
        String bin = "";
        if (rounded == 0) {
            bin = "0b0";
        } else {
            StringBuilder tmpBin = new StringBuilder();
            long i = rounded;
            while (i != 0) {
                long rem = i % 2;
                tmpBin.append(rem);
                i = i / 2;
            }
            bin = "0b";
            for (int j = tmpBin.length() - 1; j >= 0; j--) {
                bin += tmpBin.charAt(j);
            }
        }
        return bin;
    }
}

