class Solution {

    public String getClosestVowel(String word) {
        String result = "";
        String trimmedWord = word.trim();
        int length = trimmedWord.length();

        if (length < 3) {
            return result;
        }

        int startIdx = length - 1;
        boolean found = false;

        for (int i = startIdx; i >= 1 && !found; i--) {
            char currentChar = trimmedWord.charAt(i - 1);
            char prevChar = (i - 2 >= 0) ? trimmedWord.charAt(i - 2) : ' ';
            char nextChar = (i < length) ? trimmedWord.charAt(i) : ' ';

            if (currentChar != ' ' && prevChar != ' ' && nextChar != ' ') {
                if (isVowel(currentChar) && !isVowel(prevChar) && !isVowel(nextChar)) {
                    result = String.valueOf(currentChar);
                    found = true;
                }
            }
        }

        return result;
    }

    private boolean isVowel(char c) {
        return "AEIOUaeiou".indexOf(c) != -1;
    }
}

