        int dotCount = 0;
        int dotPosition = 0;
        int fileLength = 0;
        int counter = 0;
        char ch;
        String beforeDot = "";
        String afterDot = "";
        char firstChar;
        char validFlag = 'Y';

        // CALCULATE-LENGTH
        fileLength = 0;
        for (counter = 0; counter < file_name.length(); counter++) {
            if (file_name.charAt(counter) == ' ') {
                break;
            }
            fileLength++;
        }

        if (fileLength == 0) {
            return "No";
        }

        // VALIDATE-FILE-NAME
        for (counter = 0; counter < fileLength; counter++) {
            ch = file_name.charAt(counter);

            if (ch >= '0' && ch <= '9') {
                digitCount++;
            }

            if (ch == '.') {
                dotCount++;
                dotPosition = counter;
            }
        }

        if (digitCount > 3) {
            validFlag = 'N';
        }

        if (dotCount != 1) {
            validFlag = 'N';
        }

        if (dotPosition == 0) {
            validFlag = 'N';
        }

        if (dotPosition > 0 && validFlag == 'Y') {
            firstChar = file_name.charAt(0);
            if (!((firstChar >= 'a' && firstChar <= 'z') || (firstChar >= 'A' && firstChar <= 'Z'))) {
                validFlag = 'N';
            }

            counter = dotPosition + 1;
            afterDot = file_name.substring(counter, fileLength);

            if (!afterDot.equals("txt") && !afterDot.equals("exe") && !afterDot.equals("dll")) {
                validFlag = 'N';
            }
        }

