class Solution {

    public String wordsInSentence(String sentence) {
        if (sentence == null || sentence.isEmpty()) {
            return "";
        }

        int last = sentence.length() - 1;
        while (last >= 0 && sentence.charAt(last) == ' ') {
            last--;
        }
        if (last == -1) {
            return "";
        }

        StringBuilder result = new StringBuilder();
        int appendedCount = 0;
        int wordStart = -1;
        int wordLen = 0;
        boolean inWord = false;

        for (int pos = 0; pos <= last; pos++) {
            char c = sentence.charAt(pos);
            if (c == ' ') {
                if (inWord) {
                    if (isPrime(wordLen)) {
                        if (appendedCount > 0) {
                            result.append(' ');
                        }
                        result.append(sentence, wordStart, wordStart + wordLen);
                        appendedCount++;
                    }
                    inWord = false;
                    wordLen = 0;
                    wordStart = -1;
                }
            } else {
                if (!inWord) {
                    inWord = true;
                    wordStart = pos;
                    wordLen = 1;
                } else {
                    wordLen++;
                }
            }
        }

        if (inWord) {
            if (isPrime(wordLen)) {
                if (appendedCount > 0) {
                    result.append(' ');
                }
                result.append(sentence, wordStart, wordStart + wordLen);
            }
        }

        return result.toString();
    }

    private boolean isPrime(int num) {
        if (num <= 1) {
            return false;
        }
        for (int i = 2; i < num; i++) {
            if (num % i == 0) {
                return false;
            }
        }
        return true;
    }
}

