class Solution {

    public boolean simplify(String x, String n) {
        int wsXNum = 0;
        int wsXDen = 0;
        int wsNNum = 0;
        int wsNDen = 0;
        int wsResultNum = 0;
        int wsResultDen = 0;
        int wsRemainder = 0;
        int wsSlashPos = 0;
        int wsI = 0;
        String wsTempStr = "";
        int result = 0;

        // Parse first fraction (x)
        wsSlashPos = x.indexOf('/');
        wsTempStr = x.substring(0, wsSlashPos);
        wsXNum = Integer.parseInt(wsTempStr);
        wsI = wsSlashPos + 1;
        wsTempStr = x.substring(wsI);
        wsXDen = Integer.parseInt(wsTempStr);

        // Parse second fraction (n)
        wsSlashPos = n.indexOf('/');
        wsTempStr = n.substring(0, wsSlashPos);
        wsNNum = Integer.parseInt(wsTempStr);
        wsI = wsSlashPos + 1;
        wsTempStr = n.substring(wsI);
        wsNDen = Integer.parseInt(wsTempStr);

        // Multiply fractions: (x_num * n_num) / (x_den * n_den)
        wsResultNum = wsXNum * wsNNum;
        wsResultDen = wsXDen * wsNDen;

        // Check if result is a whole number
        wsRemainder = wsResultNum % wsResultDen;
        if (wsRemainder == 0) {
            result = 1;
        } else {
            result = 0;
        }

        return result == 1;
    }
}

