class Solution {

    public List<Integer> orderByPoints(List<Integer> nums) {
        int[] sums = new int[5];
        int[] result = new int[5];
        int[] numsArray = new int[5];
        for (int i = 0; i < 5; i++) {
            numsArray[i] = nums.get(i);
        }
        for (int i = 0; i < 5; i++) {
            int num = numsArray[i];
            sums[i] = 0;
            if (num >= 0) {
                while (num != 0) {
                    int digit = num % 10;
                    sums[i] += digit;
                    num = num / 10;
                }
            } else {
                num = num * -1;
                int firstDigit = 0;
                while (num >= 10) {
                    num = num / 10;
                }
                firstDigit = num;
                sums[i] = 0 - firstDigit;
                num = numsArray[i] * -1;
                while (num >= 10) {
                    int digit = num % 10;
                    sums[i] += digit;
                    num = num / 10;
                }
            }
        }
        for (int i = 0; i < 4; i++) {
            for (int j = i + 1; j < 5; j++) {
                if (sums[i] > sums[j]) {
                    int temp = sums[i];
                    sums[i] = sums[j];
                    sums[j] = temp;
                    int tempNum = numsArray[i];
                    numsArray[i] = numsArray[j];
                    numsArray[j] = tempNum;
                }
            }
        }
        for (int i = 0; i < 5; i++) {
            result[i] = numsArray[i];
        }
        List<Integer> resultList = new ArrayList<>();
        for (int i = 0; i < 5; i++) {
            resultList.add(result[i]);
        }
        return resultList;
    }
}

