class Solution {

    public boolean rightAngleTriangle(int a, int b, int c) {
        long aSquared = (long) a * a;
        long bSquared = (long) b * b;
        long cSquared = (long) c * c;

        if (aSquared + bSquared == cSquared || aSquared + cSquared == bSquared || bSquared + cSquared == aSquared) {
            return true;
        } else {
            return false;
        }
    }
}

import java.util.*;
import java.lang.*;

class Solution {

    public String findMax(List<String> words) {
        String bestWord = "";
        int bestCount = 0;

        for (String word : words) {
            String tmpWord = word.trim();
            int len = tmpWord.length();
            int count = 0;
            Set<Character> usedChars = new HashSet<>();

            for (int j = 0; j < len; j++) {
                char ch = tmpWord.charAt(j);
                if (!usedChars.contains(ch)) {
                    usedChars.add(ch);
                    count++;
                }
            }

            if (count > bestCount) {
                bestCount = count;
                bestWord = tmpWord;
            } else if (count == bestCount) {
                if (tmpWord.compareTo(bestWord) < 0) {
                    bestWord = tmpWord;
                }
            }
        }

        return bestWord;
    }
}

import java.util.*;
import java.lang.*;

class Solution {

    public List<Integer> eat(int number, int need, int remaining) {
        int wsCanEat;
        if (need <= remaining) {
            wsCanEat = need;
        } else {
            wsCanEat = remaining;
        }
        int wsEaten = number + wsCanEat;
        int wsLeft = remaining - wsCanEat;
        List<Integer> result = new ArrayList<>();
        result.add(wsEaten);
        result.add(wsLeft);
        return result;
    }
}

import java.util.*;
import java.lang.*;

class Solution {

    public int doAlgebra(List<String> operator, List<Integer> operand) {
        int wsN = 3;
        int wsI, wsK;
        int wsA, wsB, wsRes, wsExpRes, wsDivRes, wsDivRem;
        int result = 0;

        for (wsI = 0; wsI < wsN; wsI++) {
            if ("**".equals(operator.get(wsI))) {
                wsA = operand.get(wsI);
                wsB = operand.get(wsI + 1);
                wsExpRes = 1;
                for (wsK = 0; wsK < wsB; wsK++) {
                    wsExpRes *= wsA;
                }
                operand.set(wsI, wsExpRes);

                for (wsK = wsI; wsK < wsN; wsK++) {
                    operator.set(wsK, operator.get(wsK + 1));
                    operand.set(wsK + 1, operand.get(wsK + 2));
                }
                wsN--;
                wsI--;
            }
        }

        for (wsI = 0; wsI < wsN; wsI++) {
            if ("*".equals(operator.get(wsI)) || "//".equals(operator.get(wsI))) {
                wsA = operand.get(wsI);
                wsB = operand.get(wsI + 1);

                if ("*".equals(operator.get(wsI))) {
                    operand.set(wsI, wsA * wsB);
                } else {
                    wsDivRes = wsA / wsB;
                    wsDivRem = wsA % wsB;
                    operand.set(wsI, wsDivRes);
                }

                for (wsK = wsI; wsK < wsN; wsK++) {
                    operator.set(wsK, operator.get(wsK + 1));
                    operand.set(wsK + 1, operand.get(wsK + 2));
                }
                wsN--;
                wsI--;
            }
        }

        result = operand.get(0);
        for (wsI = 0; wsI < wsN; wsI++) {
            wsB = operand.get(wsI + 1);
            if ("+".equals(operator.get(wsI))) {
                result += wsB;
            } else {
                result -= wsB;
            }
        }

        return result;
    }
}

import java.util.*;
import java.lang.*;

class Solution {

    public String solve(String s) {
        String fromSet = "abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ";
        String toSet = "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz";
        int len = s.length();
        boolean hasLetter = false;

        for (int i = 0; i < len; i++) {
            if (Character.isLetter(s.charAt(i))) {
                hasLetter = true;
                break;
            }
        }

        if (hasLetter) {
            StringBuilder result = new StringBuilder(s);
            for (int i = 0; i < len; i++) {
                char c = result.charAt(i);
                int index = fromSet.indexOf(c);
                if (index != -1) {
                    result.setCharAt(i, toSet.charAt(index));
                }
            }
            return result.toString();
        } else {
            StringBuilder result = new StringBuilder();
            for (int i = len - 1; i >= 0; i--) {
                result.append(s.charAt(i));
            }
            return result.toString();
        }
    }
}

import java.util.*;
import java.lang.*;

class Solution {

    public List<Integer> generateIntegers(int a, int b) {
        List<Integer> result = new ArrayList<>();
        int start = Math.min(a, b);
        int end = Math.max(a, b);
        for (int current = start; current <= end && result.size() < 100; current++) {
            if (current >= 0 && current <= 9) {
                if (current % 2 == 0) {
                    result.add(current);
                }
            }
        }
        return result;
    }
}
